// MARK: - KeychainManager

enum KeychainError: Error, LocalizedError {
    case duplicateItem
    case unknown(OSStatus)
    case itemNotFound
    case dataConversionError

    var errorDescription: String? {
        switch self {
        case .duplicateItem:
            return "An item with the same identifier already exists in the Keychain."
        case .unknown(let status):
            return "An unknown Keychain error occurred: \(status)"
        case .itemNotFound:
            return "The requested item was not found in the Keychain."
        case .dataConversionError:
            return "Could not convert data for Keychain operation."
        }
    }
}

struct KeychainManager {
    static let serviceIdentifier = "com.cryptowallet.app"

    static func save(data: Data, key: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceIdentifier,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]

        SecItemDelete(query as CFDictionary)

        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            if status == errSecDuplicateItem {
                throw KeychainError.duplicateItem
            }
            throw KeychainError.unknown(status)
        }
    }

    static func load(key: String) throws -> Data {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceIdentifier,
            kSecAttrAccount as String: key,
            kSecReturnData as String: kCFBooleanTrue!,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]

        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)

        guard status == errSecSuccess else {
            if status == errSecItemNotFound {
                throw KeychainError.itemNotFound
            }
            throw KeychainError.unknown(status)
        }

        guard let data = item as? Data else {
            throw KeychainError.dataConversionError
        }
        return data
    }

    static func delete(key: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceIdentifier,
            kSecAttrAccount as String: key
        ]

        let status = SecItemDelete(query as CFDictionary)
        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw KeychainError.unknown(status)
        }
    }
}

// MARK: - WalletManager

class WalletManager: ObservableObject {
    @Published var currentAddress: String?
    @Published var errorMessage: String?

    private let privateKeyIdentifier = "walletPrivateKey"
    private var privateKey: P256.Signing.PrivateKey?

    init() {
        loadWallet()
    }

    func generateNewWallet() {
        do {
            privateKey = P256.Signing.PrivateKey()
            let rawRepresentation = privateKey!.rawRepresentation
            try KeychainManager.save(data: rawRepresentation, key: privateKeyIdentifier)
            updateAddress()
            errorMessage = nil
        } catch {
            errorMessage = "Failed to generate or save wallet: \(error.localizedDescription)"
        }
    }

    func loadWallet() {
        do {
            let rawRepresentation = try KeychainManager.load(key: privateKeyIdentifier)
            privateKey = try P256.Signing.PrivateKey(rawRepresentation: rawRepresentation)
            updateAddress()
            errorMessage = nil
        } catch KeychainError.itemNotFound {
            errorMessage = "No wallet found. Generate a new one."
            privateKey = nil
            currentAddress = nil
        } catch {
            errorMessage = "Failed to load wallet: \(error.localizedDescription)"
            privateKey = nil
            currentAddress = nil
        }
    }

    func deleteWallet() {
        do {
            try KeychainManager.delete(key: privateKeyIdentifier)
            privateKey = nil
            currentAddress = nil
            errorMessage = nil
        } catch {
            errorMessage = "Failed to delete wallet: \(error.localizedDescription)"
        }
    }

    func sign(message: Data) throws -> Data {
        guard let privateKey = privateKey else {
            throw WalletError.noWalletLoaded
        }
        let signature = try privateKey.signature(for: message)
        return signature.rawRepresentation
    }

    func getPublicKey() -> P256.Signing.PublicKey? {
        return privateKey?.publicKey
    }

    private func updateAddress() {
        guard let publicKey = privateKey?.publicKey else {
            currentAddress = nil
            return
        }
        let publicKeyData = publicKey.rawRepresentation
        let addressData = SHA256.hash(data: publicKeyData)
        currentAddress = "0x" + addressData.map { String(format: "%02x", $0) }.joined()
    }

    enum WalletError: Error, LocalizedError {
        case noWalletLoaded
        case signingFailed(Error)

        var errorDescription: String? {
            switch self {
            case .noWalletLoaded:
                return "No wallet is currently loaded. Please generate or load one."
            case .signingFailed(let error):
                return "Transaction signing failed: \(error.localizedDescription)"
            }
        }
    }
}

// MARK: - BlockchainService

struct BlockchainService {
    enum BlockchainError: Error, LocalizedError {
        case networkError(Error)
        case invalidResponse
        case serverError(String)
        case encodingError

        var errorDescription: String? {
            switch self {
            case .networkError(let error): return "Network error: \(error.localizedDescription)"
            case .invalidResponse: return "Received an invalid response from the blockchain service."
            case .serverError(let message): return "Blockchain service error: \(message)"
            case .encodingError: return "Failed to encode transaction data."
            }
        }
    }

    static func sendRawTransaction(rawTransactionHex: String) async throws -> String {
        guard let url = URL(string: "https://some.blockchain.node/rpc") else {
            throw BlockchainError.invalidResponse
        }

        let payload: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_sendRawTransaction",
            "params": [rawTransactionHex],
            "id": 1
        ]

        guard let httpBody = try? JSONSerialization.data(withJSONObject: payload, options: []) else {
            throw BlockchainError.encodingError
        }

        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.httpBody = httpBody
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")

        let (data, response) = try await URLSession.shared.data(for: request)

        guard let httpResponse = response as? HTTPURLResponse, httpResponse.statusCode == 200 else {
            throw BlockchainError.invalidResponse
        }

        guard let json = try? JSONSerialization.jsonObject(with: data, options: []) as? [String: Any] else {
            throw BlockchainError.invalidResponse
        }

        if let error = json["error"] as? [String: Any], let message = error["message"] as? String {
            throw BlockchainError.serverError(message)
        }

        guard let result = json["result"] as? String else {
            throw BlockchainError.invalidResponse
        }

        return result
    }
}

// MARK: - TransactionComposer

struct TransactionComposer {

    struct SimpleTransaction: Codable {
        let fromAddress: String
        let toAddress: String
        let amount: String
        let data: String?
        let timestamp: Int
    }

    static func createAndSign(
        walletManager: WalletManager,
        toAddress: String,
        amount: String,
        dataPayload: String? = nil
    ) async throws -> String {
        guard let currentAddress = walletManager.currentAddress else {
            throw WalletManager.WalletError.noWalletLoaded
        }

        let transaction = SimpleTransaction(
            fromAddress: currentAddress,
            toAddress: toAddress,
            amount: amount,
            data: dataPayload,
            timestamp: Int(Date().timeIntervalSince1970)
        )

        guard let transactionData = try? JSONEncoder().encode(transaction) else {
            throw BlockchainService.BlockchainError.encodingError
        }

        let hashedTransaction = SHA256.hash(data: transactionData)
        let hashedTransactionData = Data(hashedTransaction)

        let signatureData = try walletManager.sign(message: hashedTransactionData)

        var signedTransactionDict: [String: Any] = [
            "transaction": try JSONSerialization.jsonObject(with: transactionData, options: []) as Any,
            "signature": signatureData.hexEncodedString()
        ]

        guard let signedTransactionJsonData = try? JSONSerialization.data(withJSONObject: signedTransactionDict, options: []) else {
            throw BlockchainService.BlockchainError.encodingError
        }

        return signedTransactionJsonData.hexEncodedString()
    }
}

// MARK: - Data+HexEncoding

extension Data {
    func hexEncodedString() -> String {
        return map { String(format: "%02hhx", $0) }.joined()
    }
}

extension String {
    func dataFromHexadecimalString() -> Data? {
        let hexString = self.trimmingCharacters(in: CharacterSet(charactersIn: "<> ")).replacingOccurrences(of: " ", with: "")
        var data = Data(capacity: hexString.count / 2)
        var index = hexString.startIndex
        while index < hexString.endIndex {
            let nextIndex = hexString.index(index, offsetBy: 2)
            let byteString = String(hexString[index..<nextIndex])
            if let byte = UInt8(byteString, radix: 16) {
                data.append(byte)
            } else {
                return nil
            }
            index = nextIndex
        }
        return data
    }
}

